
-- Create proficiency questions table
CREATE TABLE public.proficiency_questions (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  section text NOT NULL,
  difficulty text NOT NULL,
  question text NOT NULL,
  passage text,
  options jsonb NOT NULL,
  correct_index int NOT NULL,
  sort_order int DEFAULT 0
);

ALTER TABLE public.proficiency_questions ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Public can view proficiency questions" ON public.proficiency_questions FOR SELECT USING (true);
CREATE POLICY "Admins can manage proficiency questions" ON public.proficiency_questions FOR ALL TO authenticated USING (public.has_role(auth.uid(), 'admin'::app_role));

